 62	static const int Sj50[size_Sj50] = {0, 1, 2, 5, 6, 7};
 63	
 64	#define size_Sj75 10
 65	static const int Sj75[size_Sj75] = {0, 1, 2, 3, 4, 7, 8, 9, 10, 11};
 66	
 67	#define size_Sj100 14
 68	static const int Sj100[size_Sj100] = {0, 1, 2, 3, 4, 5, 6, 9, 10, 11, 12, 13, 14, 15};
