 72	//------------------------------------------------------------------------------
 73	void
 74	schedule_SIB1_MBMS(module_id_t module_idP,
 75	                   frame_t frameP, sub_frame_t subframeP)
 76	//------------------------------------------------------------------------------
 77	{
 78	#ifdef SCHEDULE_SIB1_MBMS
 79	  int8_t bcch_sdu_length;
 80	  int CC_id;
 81	  eNB_MAC_INST *eNB = RC.mac[module_idP];
 82	  COMMON_channels_t *cc;
 83	  uint8_t *vrb_map;
 84	  int first_rb = -1;
 85	  int N_RB_DL;
 86	  nfapi_dl_config_request_pdu_t *dl_config_pdu;
 87	  nfapi_tx_request_pdu_t *TX_req;
 88	  nfapi_dl_config_request_body_t *dl_req;
 89	  int m, i, N_S_NB;
 90	  const int *Sj;
 91	  int n_NB = 0;
 92	  int TBS;
 93	  int k = 0, rvidx;
 94	  uint16_t sfn_sf = frameP<<4|subframeP;
 95	
 96	  for (CC_id = 0; CC_id < MAX_NUM_CCs; CC_id++) {
 97	    cc = &eNB->common_channels[CC_id];
 98	    vrb_map = (void *) &cc->vrb_map;
 99	    N_RB_DL = to_prb(cc->mib->message.dl_Bandwidth);
100	    dl_req = &eNB->DL_req[CC_id].dl_config_request_body;
101	    int foffset = cc->physCellId & 1;
102	    int sfoffset = (cc->tdd_Config == NULL) ? 0 : 1;
103	
104	    // Time-domain scheduling
105	    if (cc->mib->message.schedulingInfoSIB1_BR_r13 == 0)
106	      continue;
107	    else
108	      switch ((cc->mib->message.schedulingInfoSIB1_BR_r13 - 1) % 3) {
109	        case 0:   // repetition 4
110	          k = (frameP >> 1) & 3;
111	
112	          if ((subframeP != (4 + sfoffset))
113	              || ((frameP & 1) != foffset))
114	            continue;
115	
116	          break;
117	
118	        case 1:   // repetition 8
119	          k = frameP & 3;
120	          AssertFatal(N_RB_DL > 15,
121	                      "SIB1-BR repetition 8 not allowed for N_RB_DL= %d\n",
122	                      N_RB_DL);
123	
124	          if ((foffset == 0) && (subframeP != (4 + sfoffset)))
125	            continue;
126	          else if ((foffset == 1)
127	                   && (subframeP != ((9 + sfoffset) % 10)))
128	            continue;
129	
130	          break;
131	
132	        case 2:   // repetition 16
133	          k = ((10 * frameP) + subframeP) & 3;
134	          AssertFatal(N_RB_DL > 15,
135	                      "SIB1-BR repetition 16 not allowed for N_RB_DL= %d\n",
136	                      N_RB_DL);
137	
138	          if ((sfoffset == 1)
139	              && ((subframeP != 0) || (subframeP != 5)))
140	            continue;
141	          else if ((sfoffset == 0) && (foffset == 0)
142	                   && (subframeP != 4) && (subframeP != 9))
143	            continue;
144	          else if ((sfoffset == 0) && (foffset == 1)
145	                   && (subframeP != 0) && (subframeP != 9))
146	            continue;
147	
148	          break;
149	      }
150	
151	    // if we get here we have to schedule SIB1_BR in this frame/subframe
152	
153	    // keep counter of SIB1_BR repetitions in 8 frame period to choose narrowband on which to transmit
154	    if ((frameP & 7) == 0)
155	      cc->SIB1_BR_cnt = 0;
156	    else
157	      cc->SIB1_BR_cnt++;
158	
159	    // Frequency-domain scheduling
160	    switch (N_RB_DL) {
161	      case 6:
162	      case 15:
163	      default:
164	        m = 1;
165	        n_NB = 0;
166	        N_S_NB = 0;
167	        Sj = NULL;
168	        break;
169	
170	      case 25:
171	        m = 2;
172	        N_S_NB = 2;
173	        Sj = Sj25;
174	        break;
175	
176	      case 50:
177	        m = 2;
178	        N_S_NB = 6;
179	        Sj = Sj50;
180	        break;
181	
182	      case 75:
183	        m = 4;
184	        N_S_NB = 10;
185	        Sj = Sj75;
186	        break;
187	
188	      case 100:
189	        m = 4;
190	        N_S_NB = 14;
191	        Sj = Sj100;
192	        break;
193	    }
194	
195	    // Note: definition of k above and rvidx from 36.321 section 5.3.1
196	    rvidx = (((3 * k) >> 1) + (k & 1)) & 3;
197	    i = cc->SIB1_BR_cnt & (m - 1);
198	    if(Sj)
199	      n_NB = Sj[((cc->physCellId % N_S_NB) + (i * N_S_NB / m)) % N_S_NB];
200	    bcch_sdu_length = mac_rrc_data_req(module_idP, CC_id, frameP, BCCH_SIB1_BR, 1, &cc->BCCH_BR_pdu[0].payload[0], 0);  // not used in this case

                          .rnti = 0xffff,
                          .sysFrame = eNB->frame,
                          .subframe = eNB->subframe};
        trace_pdu(&tmp);

        if (0/*cc->tdd_Config != NULL*/) {  //TDD not for FeMBMS
          LOG_D(MAC,
                "[eNB] Frame %d : Scheduling BCCH->DLSCH (TDD) for CC_id %d SI %d bytes (mcs %d, rb 3)\n",
                frameP, CC_id, bcch_sdu_length, mcs);
        } else {
          LOG_D(MAC, "[eNB] Frame %d : Scheduling BCCH-MBMS->DLSCH (FDD) for CC_id %d SI %d bytes (mcs %d, rb 3)\n", frameP, CC_id, bcch_sdu_length, mcs);
        }

        eNB->eNB_stats[CC_id].total_num_bcch_pdu += 1;
        eNB->eNB_stats[CC_id].bcch_buffer = bcch_sdu_length;
        eNB->eNB_stats[CC_id].total_bcch_buffer += bcch_sdu_length;
        eNB->eNB_stats[CC_id].bcch_mcs = mcs;
        //printf("SI %d.%d\n", frameP, subframeP);/////////////////////////////////////////******************************
      } else {
        //LOG_D(MAC,"[eNB %d] Frame %d : BCCH not active \n",Mod_id,frame);
      }
    }
  }

  //schedule_SIB1_BR(module_idP, frameP, subframeP);
  //schedule_SI_BR(module_idP, frameP, subframeP);
  stop_meas(&eNB->schedule_si_mbms);
}

